describe('InMemoryWebhookTransport', () => {
  it('should capture and clear posted webhooks', async () => {
    const transport = new InMemoryWebhookTransport();
    const body: WebhookBody = {
      recipient: 'user-1',
      subject: 'hi',
      body: 'hello',
